import{_ as a,c as o,o as r,aj as t}from"./chunks/framework.BlveriQe.js";const u=JSON.parse('{"title":"Interface: MeAPI","description":"","frontmatter":{},"headers":[],"relativePath":"reference/js-bao-wss-client/api/interfaces/MeAPI.md","filePath":"reference/js-bao-wss-client/api/interfaces/MeAPI.md"}'),s={name:"reference/js-bao-wss-client/api/interfaces/MeAPI.md"};function n(c,e,d,i,h,l){return r(),o("div",null,[...e[0]||(e[0]=[t('<p><a href="./../README.html"><strong>js-bao-wss-client</strong></a></p><hr><p><a href="./../globals.html">js-bao-wss-client</a> / MeAPI</p><h1 id="interface-meapi" tabindex="-1">Interface: MeAPI <a class="header-anchor" href="#interface-meapi" aria-label="Permalink to “Interface: MeAPI”">​</a></h1><h2 id="methods" tabindex="-1">Methods <a class="header-anchor" href="#methods" aria-label="Permalink to “Methods”">​</a></h2><h3 id="cacheinfo" tabindex="-1">cacheInfo() <a class="header-anchor" href="#cacheinfo" aria-label="Permalink to “cacheInfo()”">​</a></h3><blockquote><p><strong>cacheInfo</strong>(): <code>Promise</code>&lt;{ <code>ageMs?</code>: <code>number</code>; <code>updatedAt?</code>: <code>string</code>; }&gt;</p></blockquote><p>Returns cache metadata for the current user&#39;s profile entry.</p><h4 id="returns" tabindex="-1">Returns <a class="header-anchor" href="#returns" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;{ <code>ageMs?</code>: <code>number</code>; <code>updatedAt?</code>: <code>string</code>; }&gt;</p><p>Object with optional <code>updatedAt</code> timestamp and <code>ageMs</code> since last refresh</p><hr><h3 id="clearcache" tabindex="-1">clearCache() <a class="header-anchor" href="#clearcache" aria-label="Permalink to “clearCache()”">​</a></h3><blockquote><p><strong>clearCache</strong>(): <code>Promise</code>&lt;<code>void</code>&gt;</p></blockquote><p>Clears the cached profile so the next get() fetches fresh data from the server.</p><h4 id="returns-1" tabindex="-1">Returns <a class="header-anchor" href="#returns-1" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<code>void</code>&gt;</p><hr><h3 id="get" tabindex="-1">get() <a class="header-anchor" href="#get" aria-label="Permalink to “get()”">​</a></h3><blockquote><p><strong>get</strong>(<code>options?</code>): <code>Promise</code>&lt;<a href="./UserProfile.html"><code>UserProfile</code></a> | <code>null</code>&gt;</p></blockquote><p>Retrieves the current user&#39;s profile, using the cache when available.</p><h4 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="options" tabindex="-1">options? <a class="header-anchor" href="#options" aria-label="Permalink to “options?”">​</a></h5><p><code>GetMeOptions</code></p><p>Controls caching and loading behavior</p><h4 id="returns-2" tabindex="-1">Returns <a class="header-anchor" href="#returns-2" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./UserProfile.html"><code>UserProfile</code></a> | <code>null</code>&gt;</p><hr><h3 id="owneddocuments" tabindex="-1">ownedDocuments() <a class="header-anchor" href="#owneddocuments" aria-label="Permalink to “ownedDocuments()”">​</a></h3><h4 id="call-signature" tabindex="-1">Call Signature <a class="header-anchor" href="#call-signature" aria-label="Permalink to “Call Signature”">​</a></h4><blockquote><p><strong>ownedDocuments</strong>(<code>options</code>): <code>Promise</code>&lt;<code>DocumentListPage</code>&gt;</p></blockquote><p>List documents the current user owns (issue #628).</p><p>Returns docs where the caller&#39;s <code>DocumentPermission.permission === &quot;owner&quot;</code>. Mirrors <a href="#shareddocuments">MeAPI.sharedDocuments</a> for parallel structure (&quot;owned-by-me&quot; vs &quot;shared-with-me&quot;).</p><p>Returns the <em>current owner</em> set (not creators) — ownership transfer updates <code>DocumentPermission.permission</code> without changing <code>Document.createdBy</code>, so this method tracks live ownership.</p><p>Inherits the same offline-first / cache-aware machinery as the (deprecated) <code>documents.list</code> reader: both call the same internal helper, with the owner filter applied across local cache, network response, and merged-result paths. The owner-only response is cached additively (<code>authoritative: false</code>) — non-owner rows from a prior <code>documents.list</code> call are NOT evicted; ownership-revocation lag is accepted as an eventual-consistency tradeoff.</p><p>Cursor format is <strong>raw JSON</strong> (matching <code>/documents</code>), NOT base64url.</p><h5 id="parameters-1" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-1" aria-label="Permalink to “Parameters”">​</a></h5><h6 id="options-1" tabindex="-1">options <a class="header-anchor" href="#options-1" aria-label="Permalink to “options”">​</a></h6><p><a href="./OwnedDocumentsOptions.html"><code>OwnedDocumentsOptions</code></a> &amp; <code>object</code></p><p>Same option set as the legacy <code>documents.list</code>.</p><h5 id="returns-3" tabindex="-1">Returns <a class="header-anchor" href="#returns-3" aria-label="Permalink to “Returns”">​</a></h5><p><code>Promise</code>&lt;<code>DocumentListPage</code>&gt;</p><h4 id="call-signature-1" tabindex="-1">Call Signature <a class="header-anchor" href="#call-signature-1" aria-label="Permalink to “Call Signature”">​</a></h4><blockquote><p><strong>ownedDocuments</strong>(<code>options?</code>): <code>Promise</code>&lt;<a href="./DocumentInfo.html"><code>DocumentInfo</code></a>&lt;<code>unknown</code>&gt;[]&gt;</p></blockquote><p>List documents the current user owns (issue #628).</p><p>Returns docs where the caller&#39;s <code>DocumentPermission.permission === &quot;owner&quot;</code>. Mirrors <a href="#shareddocuments">MeAPI.sharedDocuments</a> for parallel structure (&quot;owned-by-me&quot; vs &quot;shared-with-me&quot;).</p><p>Returns the <em>current owner</em> set (not creators) — ownership transfer updates <code>DocumentPermission.permission</code> without changing <code>Document.createdBy</code>, so this method tracks live ownership.</p><p>Inherits the same offline-first / cache-aware machinery as the (deprecated) <code>documents.list</code> reader: both call the same internal helper, with the owner filter applied across local cache, network response, and merged-result paths. The owner-only response is cached additively (<code>authoritative: false</code>) — non-owner rows from a prior <code>documents.list</code> call are NOT evicted; ownership-revocation lag is accepted as an eventual-consistency tradeoff.</p><p>Cursor format is <strong>raw JSON</strong> (matching <code>/documents</code>), NOT base64url.</p><h5 id="parameters-2" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-2" aria-label="Permalink to “Parameters”">​</a></h5><h6 id="options-2" tabindex="-1">options? <a class="header-anchor" href="#options-2" aria-label="Permalink to “options?”">​</a></h6><p><a href="./OwnedDocumentsOptions.html"><code>OwnedDocumentsOptions</code></a></p><p>Same option set as the legacy <code>documents.list</code>.</p><h5 id="returns-4" tabindex="-1">Returns <a class="header-anchor" href="#returns-4" aria-label="Permalink to “Returns”">​</a></h5><p><code>Promise</code>&lt;<a href="./DocumentInfo.html"><code>DocumentInfo</code></a>&lt;<code>unknown</code>&gt;[]&gt;</p><hr><h3 id="pendingdocumentinvitations" tabindex="-1">pendingDocumentInvitations() <a class="header-anchor" href="#pendingdocumentinvitations" aria-label="Permalink to “pendingDocumentInvitations()”">​</a></h3><blockquote><p><strong>pendingDocumentInvitations</strong>(): <code>Promise</code>&lt;<code>object</code>[]&gt;</p></blockquote><p>Lists pending document invitations for the current user.</p><h4 id="returns-5" tabindex="-1">Returns <a class="header-anchor" href="#returns-5" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<code>object</code>[]&gt;</p><hr><h3 id="shareddocuments" tabindex="-1">sharedDocuments() <a class="header-anchor" href="#shareddocuments" aria-label="Permalink to “sharedDocuments()”">​</a></h3><blockquote><p><strong>sharedDocuments</strong>(<code>options?</code>): <code>Promise</code>&lt;<a href="./SharedDocumentListResult.html"><code>SharedDocumentListResult</code></a>&gt;</p></blockquote><p>List documents shared with the current user. Includes individually-shared documents (<code>DocumentPermission</code>, non-owner) and pending legacy <code>DocumentInvitation</code>s. Pass <code>tag</code> to filter by a document tag (issue #628 — parity with <code>documents.list({ tag })</code>).</p><p>Issue #858: returns the unified <code>{ items, cursor }</code> envelope (was <code>{ documents, nextCursor }</code>) with a raw-JSON cursor (was base64url), matching <a href="#owneddocuments">MeAPI.ownedDocuments</a>. Each row carries the base <code>Document</code> fields plus the shared extras (<code>source</code>/<code>grantedBy</code>/ <code>invitationId</code>). <strong>Breaking change</strong> vs. earlier client versions.</p><h4 id="parameters-3" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-3" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="options-3" tabindex="-1">options? <a class="header-anchor" href="#options-3" aria-label="Permalink to “options?”">​</a></h5><p><a href="./SharedDocumentsOptions.html"><code>SharedDocumentsOptions</code></a></p><h4 id="returns-6" tabindex="-1">Returns <a class="header-anchor" href="#returns-6" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./SharedDocumentListResult.html"><code>SharedDocumentListResult</code></a>&gt;</p><hr><h3 id="update" tabindex="-1">update() <a class="header-anchor" href="#update" aria-label="Permalink to “update()”">​</a></h3><blockquote><p><strong>update</strong>(<code>params</code>): <code>Promise</code>&lt;<a href="./UserProfile.html"><code>UserProfile</code></a>&gt;</p></blockquote><p>Update the current user&#39;s profile (name and/or external avatar URL).</p><h4 id="parameters-4" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-4" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="params" tabindex="-1">params <a class="header-anchor" href="#params" aria-label="Permalink to “params”">​</a></h5><p><code>UpdateMeParams</code></p><p>Fields to update on the profile</p><h4 id="returns-7" tabindex="-1">Returns <a class="header-anchor" href="#returns-7" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;<a href="./UserProfile.html"><code>UserProfile</code></a>&gt;</p><hr><h3 id="uploadavatar" tabindex="-1">uploadAvatar() <a class="header-anchor" href="#uploadavatar" aria-label="Permalink to “uploadAvatar()”">​</a></h3><blockquote><p><strong>uploadAvatar</strong>(<code>imageData</code>, <code>contentType</code>): <code>Promise</code>&lt;{ <code>avatarUrl</code>: <code>string</code>; }&gt;</p></blockquote><p>Uploads an avatar image for the current user and returns the new avatar URL.</p><h4 id="parameters-5" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-5" aria-label="Permalink to “Parameters”">​</a></h4><h5 id="imagedata" tabindex="-1">imageData <a class="header-anchor" href="#imagedata" aria-label="Permalink to “imageData”">​</a></h5><p><code>ArrayBuffer</code> | <code>File</code> | <code>Blob</code></p><p>The raw image binary to upload</p><h5 id="contenttype" tabindex="-1">contentType <a class="header-anchor" href="#contenttype" aria-label="Permalink to “contentType”">​</a></h5><p><code>&quot;image/png&quot;</code> | <code>&quot;image/jpeg&quot;</code> | <code>&quot;image/gif&quot;</code> | <code>&quot;image/webp&quot;</code></p><p>MIME type of the image (must be png, jpeg, gif, or webp)</p><h4 id="returns-8" tabindex="-1">Returns <a class="header-anchor" href="#returns-8" aria-label="Permalink to “Returns”">​</a></h4><p><code>Promise</code>&lt;{ <code>avatarUrl</code>: <code>string</code>; }&gt;</p><p>Object with the new <code>avatarUrl</code></p>',95)])])}const m=a(s,[["render",n]]);export{u as __pageData,m as default};
